import{_ as d,c as o,o as p,aj as r}from"./chunks/framework.CynFBi0q.js";const l=JSON.parse('{"title":"第13章 项目管理与跨团队协作","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_13.md","filePath":"handbook/ai-product/chapter_13.md","lastUpdated":1782008855000}'),u={name:"handbook/ai-product/chapter_13.md"};function a(q,t,n,e,i,h){return p(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="第13章-项目管理与跨团队协作" tabindex="-1">第13章 项目管理与跨团队协作 <a class="header-anchor" href="#第13章-项目管理与跨团队协作" aria-label="Permalink to “第13章 项目管理与跨团队协作”">​</a></h1><p>产品经理70%的时间在设计产品，30%的时间在推动落地。能不能推动落地，决定了你的产品能不能从&quot;想法&quot;变成&quot;用户可用的东西&quot;。&quot;推动落地&quot;的能力，就是项目管理能力。</p><p>我是怕浪猫，这一章不讲PMP理论，只讲产品经理怎么在项目里当好&quot;协调者&quot;和&quot;推动者&quot;。</p><h2 id="_13-1-项目管理基础" tabindex="-1">13.1 项目管理基础 <a class="header-anchor" href="#_13-1-项目管理基础" aria-label="Permalink to “13.1 项目管理基础”">​</a></h2><h3 id="_13-1-1-产品经理在项目管理中的角色" tabindex="-1">13.1.1 产品经理在项目管理中的角色 <a class="header-anchor" href="#_13-1-1-产品经理在项目管理中的角色" aria-label="Permalink to “13.1.1 产品经理在项目管理中的角色”">​</a></h3><p>产品经理在项目中扮演什么角色？一句话：不是项目经理，但是&quot;项目推进的第一责任人&quot;。</p><p><strong>产品经理 vs 项目经理</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>产品经理</th><th>项目经理</th></tr></thead><tbody><tr><td>关注点</td><td>产品价值和方向</td><td>项目进度和质量</td></tr><tr><td>核心职责</td><td>定义产品要做什么</td><td>确保项目按时按质完成</td></tr><tr><td>决策权</td><td>功能优先级决策</td><td>资源分配和排期决策</td></tr><tr><td>沟通对象</td><td>用户、老板、业务方</td><td>研发、测试、设计</td></tr></tbody></table><p>在没有专职项目经理的团队里，产品经理要兼任项目经理的职责。这时候你的工作就变成：</p><ul><li>主持需求评审会</li><li>跟进开发进度</li><li>协调资源冲突</li><li>处理需求变更</li><li>确保按时上线</li></ul><p>怕浪猫见过太多产品经理，画原型的时候激情满满，到了推动落地就抓瞎。项目管理的本质不是&quot;管人&quot;，是&quot;理事&quot;——把混乱的事情理清楚，让每个人知道做什么、怎么做、什么时候做完。</p><h3 id="_13-1-2-敏捷开发流程" tabindex="-1">13.1.2 敏捷开发流程 <a class="header-anchor" href="#_13-1-2-敏捷开发流程" aria-label="Permalink to “13.1.2 敏捷开发流程”">​</a></h3><p>敏捷开发是互联网公司最常用的工作模式。核心是&quot;小步快跑、快速迭代&quot;。</p><p><strong>敏捷开发的核心原则</strong></p><p>原则一：个体和互动 高于 流程和工具 原则二：可工作的软件 高于 详尽的文档 原则三：客户合作 高于 合同谈判 原则四：响应变化 高于 遵循计划</p><p><strong>Scrum框架</strong></p><p>Scrum是敏捷开发最常用的框架。核心角色和流程：</p><table tabindex="0"><thead><tr><th>角色</th><th>职责</th></tr></thead><tbody><tr><td>Product Owner（产品负责人）</td><td>定义需求优先级，对产品价值负责</td></tr><tr><td>Scrum Master（敏捷教练）</td><td>确保Scrum流程被执行</td></tr><tr><td>开发团队</td><td>实现需求</td></tr></tbody></table><p><strong>Scrum流程</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Sprint规划会 → 每日站会 → Sprint开发 → Sprint评审会 → Sprint回顾会</span></span>
<span class="line"><span>      ↑                                                      |</span></span>
<span class="line"><span>      └──────── 下一个Sprint  ←──────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>一个Sprint通常是2周。每个Sprint结束时要交付一个&quot;可发布&quot;的版本。</p><p><strong>Sprint规划会的完整流程</strong></p><p>Sprint规划会是每个Sprint的起点，这个会开得好不好直接决定接下来两周的节奏。怕浪猫见过太多规划会开成了&quot;吵架会&quot;，根本原因就是流程没走对。</p><p>完整的Sprint规划会分四个阶段：</p><p>阶段一：需求拆解。产品经理把本Sprint要做的需求逐条过一遍，每个需求必须拆解到&quot;一个开发能在2天内完成&quot;的粒度。拆不细的需求先不放进来。举个例子，&quot;用户注册功能&quot;是一个Epic，拆成Story就是：注册页面UI、手机号验证逻辑、验证码发送与校验、注册成功跳转、异常处理。每个Story都要有明确的验收标准（Acceptance Criteria），不能含糊。</p><p>阶段二：Story Point估算。团队一起给每个Story打分。Story Point不是工时，是&quot;复杂度+工作量+不确定性&quot;的综合评估。1分是最简单的改动，13分基本上意味着这个Story太大需要再拆。估算方法后面会详细讲。</p><p>阶段三：承诺。研发团队根据总Story Point和历史速率（Velocity）决定本Sprint能承诺多少工作量。产品经理不要&quot;强行塞需求&quot;，而是根据团队的历史速率来合理预期。比如过去3个Sprint平均完成40分，那这次Sprint承诺36-44分是合理区间。产品经理在这个阶段的任务是：如果团队承诺不了所有需求，你要当场决定哪些需求优先级最高、哪些可以顺延。</p><p>阶段四：看板设置。把承诺的需求创建到看板上，设置&quot;待开发→开发中→测试中→已完成&quot;的列，每个Story一个卡片。产品经理要确认每个卡片的信息完整：需求描述、验收标准、关联的PRD链接、设计稿链接。不要让开发在开发过程中还要到处找资料。</p><p>Sprint规划会的时间控制也很重要。2周的Sprint，规划会不超过2小时。超过2小时说明需求准备不充分，该提前做的功课没做。</p><p><strong>每日站会的三个问题</strong></p><p>每日站会是Scrum的节奏锚点，15分钟，站着开，不多不少。每个人回答三个问题：</p><p>问题一：我昨天完成了什么？不是&quot;我在写代码&quot;，而是&quot;我完成了用户注册页面的前端开发，已提测&quot;。完成的定义是&quot;已经合并到开发分支&quot;，不是&quot;写完了但还没跑通&quot;。</p><p>问题二：我今天计划做什么？同样要具体。不是&quot;继续开发&quot;，而是&quot;今天完成注册验证码逻辑的后端接口&quot;。</p><p>问题三：有没有遇到阻碍？这是最重要的一个问题。产品经理要特别关注这个——如果开发说&quot;注册页面的设计稿还没给&quot;，那就是你的锅，赶紧去催设计。如果开发说&quot;这个接口依赖第三方，对方还没给文档&quot;，你要去推动外部协作。</p><p>怕浪猫提醒：站会不是汇报会，是同步会和排障会。如果站会变成了每个人向产品经理汇报进度，那就变味了。站会的目的是让团队成员之间互相同步，快速发现和解决问题。</p><p>产品经理在站会中的角色是&quot;听&quot;和&quot;排障&quot;，不是&quot;审&quot;和&quot;催&quot;。听出问题立刻记下来，会后一对一跟进，不要在站会上长篇讨论。</p><h3 id="_13-1-3-版本规划与排期管理" tabindex="-1">13.1.3 版本规划与排期管理 <a class="header-anchor" href="#_13-1-3-版本规划与排期管理" aria-label="Permalink to “13.1.3 版本规划与排期管理”">​</a></h3><p><strong>版本规划三步法</strong></p><p>第一步：确定版本周期。2周一个版本还是1个月一个版本？固定节奏比灵活节奏好。固定节奏的好处是：团队形成肌肉记忆，减少每次排期的沟通成本；业务方能预期什么时候能上线，不会天天追着你问进度。</p><p>第二步：根据研发容量确定版本需求。不是&quot;你想做什么&quot;，而是&quot;团队能做什么&quot;。研发容量按&quot;人天&quot;估算。</p><p>第三步：留10-15%的弹性。每个版本都要预留弹性空间，应对紧急需求插入。</p><p>怕浪猫的经验：弹性空间不是偷懒，是务实。如果你每次版本都排得满满当当，任何一个小意外都会导致延期。10-15%的弹性意味着：2周的Sprint，预留1-1.5天给突发情况。如果最后没有突发情况，那就把优先级低一点的需求提前做。</p><p><strong>排期管理工具</strong></p><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>推荐场景</th></tr></thead><tbody><tr><td>甘特图</td><td>可视化时间线</td><td>复杂项目、多团队协作</td></tr><tr><td>看板</td><td>可视化任务状态</td><td>敏捷开发、日常跟进</td></tr><tr><td>燃尽图</td><td>可视化剩余工作量</td><td>Sprint进度跟踪</td></tr></tbody></table><p><strong>需求池管理（Backlog Grooming）</strong></p><p>需求池（Backlog）不是垃圾桶，不是什么需求都往里扔就完了。需求池需要定期梳理，这个过程叫Backlog Grooming（也叫Backlog Refinement）。</p><p>Backlog Grooming的核心流程：</p><p>第一步：定期清理。每个Sprint至少做一次需求池梳理，时间建议在Sprint中期（比如第二个周四）。把需求池里的需求过一遍，过期的删除，重复的合并，描述不清的补充。</p><p>第二步：优先级排序。需求池里的需求必须按优先级排列，最上面的就是下一个Sprint最可能做的。排序的依据是&quot;价值/成本比&quot;——价值高、成本低的需求排在前面。怕浪猫的方法：用MoSCoW法则给需求打标签——Must have（必须有）、Should have（应该有）、Could have（可以有）、Won&#39;t have（这次不做）。每个版本的Must have不能超过总量的60%，否则风险太大。</p><p>第三步：需求细化。排在需求池顶部的需求要细化到可以进入Sprint的程度——有清晰的描述、验收标准、技术方案初步评估。排在底部的可以粗略一些。</p><p>第四步：估算粗排。对需求池里的需求做粗略估算（不需要精确到Story Point，用T恤尺码就行：S/M/L/XL），让产品经理心里有数，哪些需求可以放进下一个版本。</p><p>需求池管理的常见错误：</p><table tabindex="0"><thead><tr><th>错误做法</th><th>正确做法</th></tr></thead><tbody><tr><td>需求池越来越大，从不清理</td><td>每个Sprint至少清理一次</td></tr><tr><td>不排优先级，想到什么做什么</td><td>始终按价值/成本比排序</td></tr><tr><td>所有需求都写得很粗</td><td>顶部需求细化，底部粗略即可</td></tr><tr><td>一个人做需求池管理</td><td>团队一起参与梳理</td></tr></tbody></table><p><strong>Story Point估算方法（规划扑克）</strong></p><p>Story Point估算是敏捷开发中最容易吵架的环节。你说3分，他说8分，到底听谁的？怕浪猫推荐用规划扑克（Planning Poker）来解决。</p><p>规划扑克的玩法：</p><p>准备阶段：每个参与者拿一套扑克牌，牌面是斐波那契数列：1、2、3、5、8、13、21。为什么用斐波那契？因为数字越大，不确定性越高——1分和2分能区分，但20分和21分没区别，所以直接跳到21。</p><p>第一轮：产品经理介绍一个Story的内容和验收标准。每个人独立思考，选一张牌面朝下放在桌上。</p><p>第二轮：所有人同时翻牌。如果大家的分数接近（比如3、3、5），取中位数或众数即可。</p><p>第三轮：如果分数差异大（比如有人出2，有人出8），差异最大的人要解释原因。通常高分的人会指出一些低分的人没考虑到的复杂度——&quot;这个Story看起来简单，但涉及到老系统的数据迁移，测试工作量很大&quot;。讨论完后重新出牌，直到达成共识。</p><p>Story Point参考标准：</p><table tabindex="0"><thead><tr><th>分值</th><th>含义</th><th>典型案例</th></tr></thead><tbody><tr><td>1</td><td>极简单，改个文案、调个颜色</td><td>修改按钮文字</td></tr><tr><td>2</td><td>简单，逻辑清晰，无风险</td><td>新增一个配置项</td></tr><tr><td>3</td><td>中等偏简单，标准功能</td><td>新增一个表单页面</td></tr><tr><td>5</td><td>中等，有一定复杂度</td><td>接入一个新的第三方支付</td></tr><tr><td>8</td><td>复杂，有不确定性</td><td>重构用户权限体系</td></tr><tr><td>13</td><td>很复杂，建议拆分</td><td>新增IM聊天模块</td></tr><tr><td>21</td><td>太复杂，必须拆分</td><td>整体架构迁移</td></tr></tbody></table><p>怕浪猫的忠告：Story Point不是工时。1分不等于1天，5分不等于5天。Story Point衡量的是&quot;相对复杂度&quot;，不是绝对时间。团队需要花2-3个Sprint来建立自己的基准——第一个Sprint大家可能估不准，但跑几轮之后就会越来越准。</p><p>另外一个坑：不要把不同团队的Story Point拿来比较。A团队的5分和B团队的5分可能完全不是一个量级，因为基准不同。Story Point只在同一个团队内有意义。</p><h2 id="_13-2-跨团队协作实战" tabindex="-1">13.2 跨团队协作实战 <a class="header-anchor" href="#_13-2-跨团队协作实战" aria-label="Permalink to “13.2 跨团队协作实战”">​</a></h2><h3 id="_13-2-1-与研发的协作" tabindex="-1">13.2.1 与研发的协作 <a class="header-anchor" href="#_13-2-1-与研发的协作" aria-label="Permalink to “13.2.1 与研发的协作”">​</a></h3><p><strong>研发最讨厌的产品经理行为</strong></p><p>行为一：频繁改需求。PRD评审通过后还改需求，研发最烦。</p><p>行为二：需求描述不清。PRD写得像散文，研发看了三遍还不知道要做啥。</p><p>行为三：不懂技术可行性。提的需求技术上很难实现，或者要花很大代价。</p><p>行为四：催进度。研发正在写代码，产品经理每隔一小时问&quot;好了没&quot;。</p><p><strong>产品经理和研发高效协作的方法</strong></p><p>方法一：PRD评审前先和技术负责人对齐。不要在评审会上第一次讨论技术可行性。</p><p>方法二：需求变更走流程。不是&quot;不能改&quot;，而是&quot;改要评估影响&quot;。改需求前先和研发负责人评估影响，再决定是否改。</p><p>方法三：理解技术语言。不需要会写代码，但要能听懂&quot;这个接口要改&quot;、&quot;这个逻辑前端做不了&quot;意味着什么。</p><p>方法四：尊重研发的专业判断。研发说&quot;这个方案有问题&quot;，先问原因，不要直接否定。</p><p><strong>技术方案评审：产品经理要不要参加？</strong></p><p>技术方案评审是研发内部的技术讨论，产品经理是否参加一直有争议。怕浪猫的建议是：参加，但要找准自己的角色。</p><p>产品经理参加技术方案评审的目的不是&quot;指导技术方案&quot;，而是&quot;确保技术方案不偏离产品目标&quot;。具体来说：</p><p>第一，听。听技术方案的整体思路，理解他们打算怎么做。你不需要理解每个技术细节，但要理解方案的边界——这个方案能支持什么，不支持什么。比如研发说&quot;这个方案用缓存解决性能问题，但缓存会有1分钟的延迟&quot;，你就要判断：1分钟延迟用户能不能接受？如果不能，要当场提出来。</p><p>第二，问。问方案对用户体验的影响。&quot;这个方案会导致页面加载变慢吗？&quot;&quot;数据迁移期间用户能正常使用吗？&quot;这些问题研发可能不会主动考虑，但产品经理必须考虑。</p><p>第三，确认边界。技术方案评审经常会出现&quot;这个功能先不做&quot;的妥协。产品经理要确认这些妥协是否影响核心功能。如果不影响，同意；如果影响，要当场讨论替代方案。</p><p>产品经理在技术方案评审中不该做的事：不要提&quot;能不能换个技术方案&quot;，除非你对技术有足够的理解。不要在技术方案评审中重新讨论&quot;要不要做这个功能&quot;，这是需求评审的议题。</p><p><strong>代码Review中产品经理的角色</strong></p><p>代码Review是研发的日常工作，产品经理通常不参与。但有一个场景产品经理必须关注：涉及业务逻辑的核心代码变更。</p><p>产品经理怎么参与代码Review？不是让你去读代码，而是关注这几个问题：</p><p>第一，验收标准是否被满足。研发说&quot;做完了&quot;，但代码逻辑是否真的覆盖了所有验收标准？产品经理可以请研发走一遍核心流程，对照验收标准逐条确认。</p><p>第二，边界条件是否处理。正常流程通常没问题，边界条件才是bug的高发区。&quot;用户没有绑定手机号时会怎样？&quot;&quot;网络超时会怎样？&quot;&quot;并发提交会怎样？&quot;把这些边界条件列出来，请研发确认代码中是否有处理。</p><p>第三，数据埋点是否到位。很多功能上线后才发现没埋点，导致无法评估效果。产品经理要在代码Review阶段确认关键行为是否有埋点——页面曝光、按钮点击、转化漏斗。</p><p>怕浪猫的经验总结：产品经理不需要会写代码，但要能看懂&quot;代码逻辑是不是对的产品逻辑&quot;。你是产品逻辑的最后守门人。</p><h3 id="_13-2-2-与设计的协作" tabindex="-1">13.2.2 与设计的协作 <a class="header-anchor" href="#_13-2-2-与设计的协作" aria-label="Permalink to “13.2.2 与设计的协作”">​</a></h3><p><strong>设计最讨厌的产品经理行为</strong></p><p>行为一：原型画得太细，限制了设计的发挥空间。</p><p>行为二：评审时不停地提&quot;我觉得这里颜色不对&quot;、&quot;这个按钮大一点&quot;——微观管理。</p><p>行为三：需求变了不通知设计，设计按老需求做完了才发现需求改了。</p><p><strong>产品经理和设计高效协作的方法</strong></p><p>方法一：给设计足够的发挥空间。原型只需要表达&quot;功能逻辑&quot;，不需要表达&quot;视觉风格&quot;。</p><p>方法二：评审时关注&quot;功能完整性&quot;而非&quot;视觉细节&quot;。视觉细节是设计师的专业领域。</p><p>方法三：需求变更第一时间通知设计。设计排期通常很紧，需求变更不及时通知，设计就要返工。</p><p>方法四：提供完整的交互说明。原型图只是骨架，交互说明才是血肉。点击按钮跳转到哪里？弹窗的内容是什么？列表为空时怎么显示？这些细节如果不写清楚，设计师要么猜，要么反复问你，效率都很低。</p><h3 id="_13-2-3-需求评审与沟通技巧" tabindex="-1">13.2.3 需求评审与沟通技巧 <a class="header-anchor" href="#_13-2-3-需求评审与沟通技巧" aria-label="Permalink to “13.2.3 需求评审与沟通技巧”">​</a></h3><p><strong>需求评审会的准备</strong></p><p>准备一：PRD提前发给参会人员。至少提前1天发，让大家有时间提前看。</p><p>准备二：准备评审大纲。评审会不是&quot;读PRD&quot;，而是&quot;讨论关键决策&quot;。大纲包括：背景、目标、核心功能、待讨论的决策点。</p><p>准备三：准备备用方案。如果有争议的功能，提前准备A/B两个方案，评审时讨论选哪个。</p><p><strong>需求评审会的进行</strong></p><p>进行一：控制时间。1小时的评审会，前15分钟讲背景和目标，中间30分钟讨论核心功能，最后15分钟确认待办事项。</p><p>进行二：引导讨论。有人跑题了要及时拉回来。有人说&quot;我觉得这个功能不对&quot;，要追问&quot;为什么不对，你的建议是什么&quot;。</p><p>进行三：记录决策。评审会上的每一个决策都要记录，会后发出会议纪要。</p><p><strong>评审会的常见问题和应对</strong></p><p>需求评审会是冲突的高发地带。怕浪猫总结三大常见问题及应对方法：</p><p>问题一：需求不清晰。评审会上有人问&quot;这个功能具体怎么做&quot;，你回答不了——说明PRD写得不够细。</p><p>应对方法：当场记录问题，会后补充PRD，不要在会上临时拍脑袋。一个模糊的需求进开发，出来的东西一定不是你想要的。如果问题太多，说明PRD质量不达标，应该暂停评审，补充完善后再开。宁可多花一天写PRD，也不要让开发做两天发现方向不对。</p><p>问题二：技术可行性争议。研发说&quot;这个做不了&quot;，产品经理说&quot;竞品已经做了&quot;。</p><p>应对方法：不要在评审会上硬刚。先问清楚&quot;做不了&quot;的具体原因——是技术架构限制？是性能瓶颈？是工期不够？不同原因有不同的应对方式。技术架构限制可以讨论替代方案；性能瓶颈可以讨论是否做降级处理；工期不够可以讨论分阶段实现。怕浪猫的原则：把&quot;做不了&quot;翻译成&quot;什么条件下能做&quot;，然后评估这些条件是否值得。</p><p>问题三：排期冲突。需求评审通过，但排期排不上。研发说&quot;这个Sprint做不了&quot;，产品经理说&quot;老板说必须这版上&quot;。</p><p>应对方法：回到优先级。把本Sprint所有需求和这个新需求放在一起排优先级，如果新需求优先级最高，那就把最低优先级的需求移出去。不要试图&quot;加塞&quot;——Sprint的容量是有限的，加塞只会导致质量下降或延期。如果老板要求必须上，那就让老板做选择：&quot;要做这个，就得把那个推迟，您选哪个？&quot;</p><p>评审会问题应对速查表：</p><table tabindex="0"><thead><tr><th>问题类型</th><th>典型表现</th><th>应对策略</th></tr></thead><tbody><tr><td>需求不清晰</td><td>多人提出疑问、理解不一致</td><td>暂停评审，补充PRD后再开</td></tr><tr><td>技术可行性争议</td><td>研发说做不了</td><td>追问原因，讨论替代方案或分阶段实现</td></tr><tr><td>排期冲突</td><td>需求超出Sprint容量</td><td>回到优先级排序，做取舍</td></tr><tr><td>需求范围蔓延</td><td>评审中不断加新需求</td><td>冻结范围，新增需求进需求池</td></tr><tr><td>决策僵局</td><td>两种方案各有利弊，无法统一</td><td>记录分歧，升级决策或小流量验证</td></tr></tbody></table><p><strong>沟通技巧</strong></p><p>技巧一：先听后说。别人发言时认真听，不要急着反驳。</p><p>技巧二：用数据说话。争议时用数据支撑你的观点，而不是&quot;我觉得&quot;。</p><p>技巧三：承认不确定性。&quot;这个功能的效果我也不能100%确定，所以我们需要小流量测试验证&quot;——这比&quot;这个功能肯定有效&quot;更可信。</p><p>技巧四：把&quot;不行&quot;换成&quot;可以，如果&quot;。不要直接说&quot;这个方案不行&quot;，而是说&quot;这个方案可以，如果我们能接受XXX的代价&quot;。把否定变成选择，对方更容易接受。</p><p>技巧五：会后书面确认。口头达成的共识不可靠，会后一定要发邮件或文档确认。怕浪猫踩过的坑：会上大家都说&quot;OK&quot;，会后各有各的理解，最后做出来的东西和预期完全不一样。书面确认不是为了甩锅，是为了对齐。</p><h3 id="_13-2-4-与运营的协作" tabindex="-1">13.2.4 与运营的协作 <a class="header-anchor" href="#_13-2-4-与运营的协作" aria-label="Permalink to “13.2.4 与运营的协作”">​</a></h3><p>产品经理和运营的协作关系很微妙——你们服务的对象相同（用户和业务），但看问题的角度不同。产品经理从&quot;系统能力&quot;出发，运营从&quot;业务目标&quot;出发。角度不同不意味着对立，恰恰意味着互补。</p><p><strong>运营需求管理</strong></p><p>运营是最活跃的需求来源之一。每次活动、每个渠道、每个增长实验，都可能产生产品需求。但运营需求有个特点：多、碎、急。如果不加管理，产品团队会被运营需求淹没。</p><p>运营需求管理的核心是&quot;过滤&quot;和&quot;排序&quot;。</p><p>过滤第一层：这个需求是&quot;一次性&quot;还是&quot;可持续&quot;的？一次性的需求（比如某个节日活动的特殊页面）不值得投入产品化，用运营工具或临时方案解决即可。可持续的需求（比如用户分层推送能力）才值得产品化。怕浪猫的判断标准：如果这个需求未来3个月还会出现至少2次，就值得产品化。</p><p>过滤第二层：这个需求的ROI如何？运营提需求的时候通常只说&quot;为什么要做&quot;，不说&quot;做了之后预期效果是什么&quot;。产品经理要追问：预期的用户量是多少？预期的转化率提升是多少？预期的营收贡献是多少？如果运营说不出来，说明这个需求还没有想清楚，先回去想清楚再来。</p><p>过滤第三层：这个需求是否和产品规划冲突？运营的视角是短期、局部的，产品的视角是长期、全局的。有些运营需求短期有效但长期有害——比如&quot;在首页加一个大弹窗推活动&quot;，短期转化好，但长期伤害用户体验。产品经理要做全局判断。</p><p>运营需求过滤决策表：</p><table tabindex="0"><thead><tr><th>维度</th><th>通过</th><th>拒绝</th></tr></thead><tbody><tr><td>持续性</td><td>未来会反复出现</td><td>仅一次使用</td></tr><tr><td>ROI</td><td>有明确预期效果且值得投入</td><td>无法量化或投入产出不成比例</td></tr><tr><td>规划一致性</td><td>与产品方向一致</td><td>与长期规划冲突</td></tr><tr><td>技术可行性</td><td>现有能力可支撑</td><td>需要大量额外开发</td></tr></tbody></table><p>过滤之后是排序。通过了过滤的运营需求，和产品规划中的需求放在一起，用同样的优先级标准排序。不要因为是运营提的就有特权，也不要因为是产品规划的就天然高优先级。优先级的唯一标准是&quot;对业务的价值&quot;。</p><p><strong>活动方案评审：运营活动的产品化思维</strong></p><p>运营做活动，产品经理要参与评审。这不是&quot;找茬&quot;，是帮助运营把活动做得更好。</p><p>产品经理在活动方案评审中关注三个维度：</p><p>维度一：用户体验。运营设计活动的时候天然偏向&quot;刺激转化&quot;，容易忽略用户体验。比如活动规则太复杂、参与门槛太高、奖励兑现路径太长。产品经理要从用户视角审视：用户能不能在10秒内理解这个活动？参与流程是否顺畅？奖励是否即时可得？</p><p>维度二：系统能力。运营策划活动的时候不一定了解系统的边界。产品经理要评估：活动预估的峰值流量系统能不能扛？奖品库存管理是否到位？活动页面的加载速度是否可接受？怕浪猫经历过一次惨痛教训：运营搞了个限时秒杀活动，预估1万人参与，结果来了10万人，系统直接崩了。从那以后，每次活动评审我都会问：峰值预估是多少？有没有限流方案？</p><p>维度三：数据闭环。活动做完不是结束，要能评估效果。产品经理要在活动方案评审时确认：活动页面是否有完整的数据埋点？转化漏斗的每个环节是否可追踪？活动的核心指标是什么（DAU、GMV、新用户数）？没有数据闭环的活动就是&quot;盲打&quot;，做完了也不知道有没有效果。</p><p>活动方案评审检查清单：</p><table tabindex="0"><thead><tr><th>检查项</th><th>具体内容</th><th>常见遗漏</th></tr></thead><tbody><tr><td>活动规则</td><td>规则是否简洁、无歧义</td><td>规则漏洞被薅羊毛</td></tr><tr><td>参与流程</td><td>步骤是否最少化</td><td>流程太长导致流失</td></tr><tr><td>奖励机制</td><td>奖励是否有吸引力、能否即时兑现</td><td>奖励延迟导致用户投诉</td></tr><tr><td>流量预估</td><td>峰值流量和限流方案</td><td>流量超预期导致系统崩溃</td></tr><tr><td>数据埋点</td><td>页面曝光、按钮点击、转化漏斗</td><td>缺埋点导致无法评估效果</td></tr><tr><td>风控方案</td><td>防刷机制、异常监控</td><td>被黑产薅羊毛</td></tr><tr><td>灰度方案</td><td>是否需要小流量验证</td><td>全量上线出问题影响面大</td></tr><tr><td>下线方案</td><td>活动结束后如何平滑下线</td><td>活动页面残留导致用户困惑</td></tr></tbody></table><p>产品经理和运营的协作，核心是&quot;互相补位&quot;。运营补产品的业务敏感度，产品补运营的系统思维。怕浪猫的建议：每两周和运营负责人喝杯咖啡，了解他们最近在做什么、遇到什么问题。不要等运营提需求了才沟通，主动了解才能提前规划。</p><blockquote><p>跨团队协作的核心不是&quot;说服别人&quot;，而是&quot;对齐目标&quot;。当所有人的目标一致时，协作就顺畅了。</p></blockquote><p>本章小结：产品经理的项目管理能力决定了产品能不能落地。敏捷开发、版本规划、跨团队协作——这些&quot;软技能&quot;和&quot;硬技能&quot;同样重要。记住：推动落地，才是产品经理真正的价值。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>产品经理角色</td><td>项目推进的第一责任人</td></tr><tr><td>敏捷开发</td><td>小步快跑、快速迭代</td></tr><tr><td>Scrum框架</td><td>Product Owner + Scrum Master + 开发团队</td></tr><tr><td>Sprint规划会</td><td>需求拆解→估算→承诺→看板，四个阶段缺一不可</td></tr><tr><td>每日站会</td><td>昨天做了什么、今天做什么、有什么阻碍</td></tr><tr><td>版本规划</td><td>固定周期+研发容量+弹性空间</td></tr><tr><td>需求池管理</td><td>定期清理、优先级排序、顶部细化、粗略估算</td></tr><tr><td>Story Point估算</td><td>规划扑克，相对复杂度而非绝对工时</td></tr><tr><td>与研发协作</td><td>提前对齐、变更走流程、理解技术语言、参加方案评审</td></tr><tr><td>与设计协作</td><td>给空间、看功能、快通知、写清楚交互</td></tr><tr><td>需求评审</td><td>提前准备、控制时间、记录决策、应对三类常见问题</td></tr><tr><td>与运营协作</td><td>过滤一次性需求、ROI驱动排序、活动评审三维度</td></tr></tbody></table><p>觉得有用？收藏起来，下次做项目管理直接照抄框架。</p><p>你遇到过最坑的跨团队协作经历是什么？评论区说说。</p><p>关注怕浪猫，下期我们讲&quot;产品上线与持续优化&quot;——上线不是结束，而是开始。怕浪猫教你怎么做好上线后的持续优化。</p><p>系列进度 13/16</p><p><strong>下章预告：</strong> 第14章，产品上线不是终点，而是起点。数据监控、用户反馈、快速迭代——上线后的工作比上线前更重要。怕浪猫带你走一遍产品上线的完整流程。</p>`,153)])])}const b=d(u,[["render",a]]);export{l as __pageData,b as default};
